// Webhook POST payloads arrive nested under .body
const incoming = $input.first().json;
const transcript = incoming.body?.transcript ?? incoming.transcript;

if (!transcript) throw new Error('No transcript provided');

const prompt = `You are a meeting analyst. Given the transcript below, extract:

1. A 2-3 sentence meeting summary
2. Key decisions made (as a list of strings)
3. Action items, each with:
   - task (string)
   - owner (name or "Unassigned")
   - deadline (date string or "Not specified")
   - priority ("High", "Medium", or "Low")

Return ONLY valid JSON matching this exact shape, no explanation, no markdown:
{
  "summary": "...",
  "decisions": ["..."],
  "actionItems": [
    { "task": "...", "owner": "...", "deadline": "...", "priority": "High" }
  ]
}

Transcript:
${transcript}`;

// n8n Code nodes do not expose global fetch in all versions — use the built-in helper.
let data;
try {
  data = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': $env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: {
      model: $env.ANTHROPIC_MODEL || 'claude-sonnet-4-5-20250929',
      max_tokens: 2000,
      messages: [{ role: 'user', content: prompt }]
    },
    json: true
  });
} catch (e) {
  const detail = e.response?.body ? JSON.stringify(e.response.body) : e.message;
  throw new Error(`Anthropic API error: ${detail}`);
}

const raw = data.content?.[0]?.text || '';

let parsed;
try {
  parsed = JSON.parse(raw);
} catch {
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('Claude returned non-JSON: ' + raw.slice(0, 300));
  parsed = JSON.parse(match[0]);
}

return [{
  json: {
    extraction: parsed,
    rawTranscript: transcript
  }
}];

// Webhook POST payloads arrive nested under .body
const incoming = $input.first().json;
const body = incoming.body ?? incoming;
const items = body.actionItems || [];
return items.map(item => ({
  json: {
    task: item.task,
    owner: item.owner,
    deadline: item.deadline,
    priority: item.priority,
    summary: body.summary,
    decisions: body.decisions,
    attendeeEmails: body.attendeeEmails,
    notionDatabaseId: body.notionDatabaseId
  }
}));

const items = $input.all();
if (items.length === 0) return [];

const notionKey = $env.NOTION_API_KEY;
const dbId = items[0].json.notionDatabaseId;

if (!notionKey) throw new Error('NOTION_API_KEY not set in environment');
if (!dbId) throw new Error('notionDatabaseId not provided');

// Notion API version 2025-09-03: databases are containers of data sources;
// pages are created against a data source, not the database.
const headers = {
  'Authorization': `Bearer ${notionKey}`,
  'Notion-Version': '2025-09-03',
  'Content-Type': 'application/json'
};

// 1) Retrieve the database to get its data source IDs (once for the whole batch).
let db;
try {
  db = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.notion.com/v1/databases/${dbId}`,
    headers,
    json: true
  });
} catch (e) {
  const detail = e.response?.body ? JSON.stringify(e.response.body) : e.message;
  throw new Error(`Notion: could not read database (check the ID and that the "Recap" integration is connected to it): ${detail}`);
}

const dataSources = db.data_sources || [];
if (dataSources.length === 0) throw new Error('Notion database has no data sources.');
const dataSourceId = dataSources[0].id;

// 2) Read the data source schema once.
let ds;
try {
  ds = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.notion.com/v1/data_sources/${dataSourceId}`,
    headers,
    json: true
  });
} catch (e) {
  const detail = e.response?.body ? JSON.stringify(e.response.body) : e.message;
  throw new Error(`Notion: could not read data source schema: ${detail}`);
}

const props = ds.properties || {};
const titlePropName = Object.keys(props).find(k => props[k].type === 'title');
if (!titlePropName) throw new Error('Notion data source has no Title property.');

function buildValue(name, value) {
  const prop = props[name];
  if (!prop) return null;
  switch (prop.type) {
    case 'title':      return { title: [{ text: { content: value } }] };
    case 'rich_text':  return { rich_text: [{ text: { content: value } }] };
    case 'select':     return { select: { name: value } };
    case 'status':     return { status: { name: value } };
    case 'date':       return { date: { start: value } };
    case 'number': {
      const num = Number(value);
      return Number.isFinite(num) ? { number: num } : null;
    }
    default:           return { rich_text: [{ text: { content: value } }] };
  }
}

// 3) Create one page per action item.
const out = [];
for (const it of items) {
  const item = it.json;
  const properties = {};
  properties[titlePropName] = buildValue(titlePropName, item.task || 'Untitled Task');

  const maybe = (name, value) => {
    if (props[name] && value != null && value !== '') {
      const v = buildValue(name, value);
      if (v) properties[name] = v;
    }
  };

  maybe('Owner', item.owner || 'Unassigned');
  if (props['Deadline']) {
    if (props['Deadline'].type === 'date') {
      const d = new Date(item.deadline);
      if (!isNaN(d.getTime())) properties['Deadline'] = { date: { start: d.toISOString().slice(0,10) } };
    } else {
      maybe('Deadline', item.deadline || 'Not specified');
    }
  }
  maybe('Priority', item.priority || 'Medium');
  maybe('Status', 'Not started');

  let data;
  try {
    data = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.notion.com/v1/pages',
      headers,
      body: { parent: { type: 'data_source_id', data_source_id: dataSourceId }, properties },
      json: true
    });
  } catch (e) {
    const detail = e.response?.body ? JSON.stringify(e.response.body) : e.message;
    throw new Error(`Notion API error creating task "${item.task}": ${detail}`);
  }

  out.push({ json: {
    notionPageId: data.id,
    notionUrl: data.url,
    task: item.task,
    attendeeEmails: item.attendeeEmails,
    summary: item.summary,
    decisions: item.decisions,
    notionDatabaseId: item.notionDatabaseId
  }});
}

return out;

const item = $input.first().json;
const sgKey = $env.SENDGRID_API_KEY;
const fromEmail = $env.SENDGRID_FROM_EMAIL;

if (!sgKey) throw new Error('SENDGRID_API_KEY not set in environment');
if (!fromEmail) throw new Error('SENDGRID_FROM_EMAIL not set in environment');

const toList = (item.emailList || []).map(email => ({ email: email.trim() })).filter(e => e.email.includes('@'));

if (toList.length === 0) {
  return [{ json: { skipped: true, reason: 'No valid recipient emails', notionUrl: item.notionUrl, taskCount: item.taskCount } }];
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.sendgrid.com/v3/mail/send',
    headers: {
      'Authorization': `Bearer ${sgKey}`,
      'Content-Type': 'application/json'
    },
    body: {
      personalizations: [{ to: toList }],
      from: { email: fromEmail, name: 'Recap' },
      subject: 'Meeting summary & action items',
      content: [{ type: 'text/html', value: item.html }]
    },
    json: true
  });
} catch (e) {
  const detail = e.response?.body ? JSON.stringify(e.response.body) : e.message;
  throw new Error(`SendGrid error: ${detail}`);
}

return [{ json: { emailSent: true, recipients: toList.length, notionUrl: item.notionUrl, taskCount: item.taskCount } }];

const item = $input.first().json;
return [{ json: {
  notionUrl: item.notionUrl || '',
  taskCount: item.taskCount || 0,
  emailsSent: item.recipients || 0
} }];
